      entries.push({ id:`AL_SEED_${p.id}_TX1`, ts:new Date(now - (60+i*3)*dayMs).toISOString(), entityType:"property", entityId:p.id, entityLabel:p.label, action:"add-transaction", changes:[], user:"You" });
